#nullable enable // autogenerated

using MVZ2Logic;
using MVZ2Logic.Entities;
using MVZ2Logic.Definitions;
using MVZ2Logic.Definitions;
using MVZ2Logic.Options;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.skipTalks)]
    public class SkipTalksOptionToggle : OptionToggleDefinition
    {
        public SkipTalksOptionToggle(string nsp, string name) : base(nsp, name)
        {
        }
        public override bool GetValue(IOptionContext context)
        {
            return Global.Options.GetOptionBool(LogicOptionItemID.skipTalks);
        }

        public override void OnValueChanged(IOptionContext context, bool value)
        {
            Global.Options.SetOptionBool(LogicOptionItemID.skipTalks, value);
            Global.Options.SaveOptions();
        }
    }
}
